fn main() {
    let my_first_initial = 'C';
    if my_first_initial != 'C' {
        println!("Not C!");
    } else {
        println!("It's C!");
    }

    let your_character = 'R';
    if your_character != 'C' {
        println!("Your character is not C!");
    } else {
        println!("Your character is C!");
    }
}
